SELECT rt.id, rt.template_name, rt.template_code, rt.description, rt.check_template_id, ct.template_name as check_template_name, ct.template_code as check_template_code, rt.is_default, rt.status, rt.created_at, rt.updated_at, COUNT(DISTINCT rr.id) as rule_count FROM rating_templates rt LEFT JOIN check_templates ct ON rt.check_template_id = ct.id AND ct.deleted = 0 LEFT JOIN rating_rules rr ON rt.id = rr.rating_template_id AND rr.deleted = 0
rt.deleted = 0
AND rt.template_name LIKE CONCAT('%', #{query.templateName}, '%')
AND rt.template_code LIKE CONCAT('%', #{query.templateCode}, '%')
AND rt.check_template_id = #{query.checkTemplateId}
AND rt.status = #{query.status}
AND rt.is_default = #{query.isDefault}
GROUP BY rt.id ORDER BY rt.is_default DESC, rt.created_at DESC
